class Solution:
    def compress(self, chars):
        # Build compressed version as a list then overwrite
        groups = []
        i = 0
        while i < len(chars):
            c = chars[i]
            j = i
            while j < len(chars) and chars[j] == c:
                j += 1
            groups.append((c, j - i))
            i = j
        write = 0
        for c, cnt in groups:
            chars[write] = c
            write += 1
            if cnt > 1:
                for ch in str(cnt):
                    chars[write] = ch
                    write += 1
        return write

