var compress = function(chars) {
    let write = 0, i = 0;
    while (i < chars.length) {
        const c = chars[i];
        let j = i;
        while (j < chars.length && chars[j] === c) j++;
        chars[write++] = c;
        const run = j - i;
        if (run > 1) {
            for (const ch of String(run)) {
                chars[write++] = ch;
            }
        }
        i = j;
    }
    return write;
};
